    def _encode_for_disk(self, value: Any) -> bytes:
        """Serialize a value for the on-disk cache, optionally compressing it.

        The resulting blob is prefixed with a magic header (`b"DSPC"`) plus a 1-byte codec
        selector so that `_decode_from_disk` can tell compressed/uncompressed DSPy blobs apart
        from pre-existing (header-less) cache entries written before this feature existed.
        """
        payload = pickle.dumps(value)
        codec_byte = _CODEC_NAME_TO_BYTE[self.compress]
        if self.compress == "gzip":
            payload = gzip.compress(payload)
        elif self.compress == "zlib":
            payload = zlib.compress(payload)
        return _CACHE_MAGIC + bytes([codec_byte]) + payload

    def _decode_from_disk(self, raw: Any) -> Any:
        """Deserialize a value fetched from the on-disk cache.

        Values written by `_encode_for_disk` are raw bytes starting with the `b"DSPC"` magic
        header. Anything else (including bytes without the header) is a legacy, pre-feature
        cache entry and is returned/unpickled as-is for backward compatibility.
        """
        if not isinstance(raw, bytes):
            # Legacy entries are stored as arbitrary Python objects and already deserialized by
            # diskcache itself.
            return raw

        if raw[:4] != _CACHE_MAGIC:
            # Legacy raw pickle bytes written before the magic header existed.
            return pickle.loads(raw)

        codec_byte = raw[4]
        payload = raw[5:]
        if codec_byte == _CODEC_GZIP:
            payload = gzip.decompress(payload)
        elif codec_byte == _CODEC_ZLIB:
            payload = zlib.decompress(payload)
        return pickle.loads(payload)

